// 991  if (auto *II = dyn_cast<IntrinsicInst>(I)) {
// 992    if (II->getIntrinsicID() == Intrinsic::ptrmask) {
// 993      // If we are masking off the low bits of a GEP, we may be able to simplify
// 994      // the GEP.
// 995      Value *Ptr = II->getArgOperand(0);
// 996      auto *Mask = dyn_cast<ConstantInt>(II->getArgOperand(1));
// 997      if (!Mask)
// 998        return false;
// 999
//1000      auto *GEP = cast<GetElementPtrInst>(Ptr);
//1001      if (GEP->hasAllConstantIndices()) {
//1002        // We can't simplify this GEP if it has any non-constant indices.
//1003        // TODO: We could try to simplify the GEP if the non-constant indices
//1004        // are only in the high bits of the pointer.
//1005        return false;
//1006      }
// ...
```

